function daemonizeAndExit(originalArgv) {
  const childArgs = originalArgv.slice(2).filter((arg) => {
    if (arg === "--daemon")
      return false;
    if (arg.startsWith("--daemon="))
      return false;
    return true;
  });
  childArgs.push("--internal-daemon-child");
  const bunExe = process.execPath;
  const scriptPath = originalArgv[1];
  const child = Bun.spawn([bunExe, "run", scriptPath, ...childArgs], {
    stdio: ["ignore", "ignore", "ignore"],
    cwd: process.cwd(),
    env: process.env
  });
  child.unref?.();
  console.log(`hotbuns daemonized as pid ${child.pid}`);
  process.exit(0);
}
